INSERT INTO learning_blocks (lang, lb_id, difficulty, page, title, tags, summary, content, eg_in, eg_out) VALUES 
('python', 106, 'intermediate', 1, '打开文件并指定模式', '["文件","打开"]', '学习如何使用open()函数以不同模式打开文件。', 'open()函数用于打开文件，返回文件对象。\\n模式参数指定文件访问方式，如读取(r)、写入(w)、追加(a)等。\\n建议使用with语句来自动管理文件资源。', '["file = open(\\"example.txt\\", \\"r\\")", "with open(\\"data.txt\\", \\"w\\") as f:"]', '["", ""]'),
('python', 107, 'intermediate', 1, '读取整个文件内容', '["文件","读取"]', '使用read()方法一次性读取文件的全部内容。', 'read()方法返回文件中的所有字符作为字符串。\\n适用于小文件，对于大文件可能消耗大量内存。\\n读取后文件指针移动到文件末尾。', '["with open(\\"file.txt\\", \\"r\\") as f:\\n    content = f.read()", "file = open(\\"data.txt\\", \\"r\\")\\ncontent = file.read()\\nfile.close()"]', '["\\"文件内容文本\\"", "\\"数据内容\\""]'),
('python', 108, 'intermediate', 1, '逐行读取文件', '["文件","读取","行"]', '使用readline()或readlines()方法逐行处理文件内容。', 'readline()每次读取一行，返回字符串；readlines()读取所有行并返回列表。\\n适用于处理大文件或需要逐行分析的情况。\\n常用for循环直接迭代文件对象进行逐行读取。', '["with open(\\"file.txt\\", \\"r\\") as f:\\n    line = f.readline()", "lines = []\\nwith open(\\"data.txt\\", \\"r\\") as f:\\n    for line in f:\\n        lines.append(line)"]', '["\\"第一行内容\\"", "[\\"行1\\", \\"行2\\", \\"行3\\"]"]'),
('python', 109, 'intermediate', 1, '写入文件并覆盖', '["文件","写入"]', '使用write()方法将字符串写入文件，如果文件存在则覆盖。', '以写入模式(\\"w\\")打开文件会清空原有内容。\\nwrite()接受字符串参数，不会自动添加换行符。\\n可以使用writelines()写入字符串列表。', '["with open(\\"output.txt\\", \\"w\\") as f:\\n    f.write(\\"Hello World\\")", "lines = [\\"line1\\\\n\\", \\"line2\\\\n\\"]\\nwith open(\\"file.txt\\", \\"w\\") as f:\\n    f.writelines(lines)"]', '["", ""]'),
('python', 110, 'intermediate', 1, '追加内容到文件', '["文件","追加"]', '以追加模式(\\"a\\")打开文件，在文件末尾添加新内容。', '追加模式不会清空文件，新内容写入到文件尾部。\\n适用于日志记录或数据累积场景。\\n使用write()或writelines()方法进行追加。', '["with open(\\"log.txt\\", \\"a\\") as f:\\n    f.write(\\"New log entry\\\\n\\")", "file = open(\\"data.txt\\", \\"a\\")\\nfile.write(\\"additional data\\")\\nfile.close()"]', '["", ""]'),
('python', 111, 'intermediate', 1, '使用with语句管理文件', '["文件","上下文管理器"]', '通过with语句自动管理文件对象的打开和关闭，避免资源泄漏。', 'with语句确保文件在退出块时正确关闭，即使发生异常。\\n这是处理文件的推荐方式，提高代码健壮性。\\n可以同时打开多个文件，用逗号分隔。', '["with open(\\"file1.txt\\", \\"r\\") as f1, open(\\"file2.txt\\", \\"w\\") as f2:\\n    data = f1.read()\\n    f2.write(data)", "try:\\n    with open(\\"test.txt\\", \\"r\\") as f:\\n        content = f.read()\\nexcept FileNotFoundError:\\n    print(\\"文件不存在\\")"]', '["", "\\"文件不存在\\""]'),
('python', 112, 'intermediate', 1, '文件指针操作', '["文件","指针","seek","tell"]', '使用seek()和tell()方法控制和查询文件指针的位置。', '文件指针表示当前读写位置。\\nseek(offset, whence)移动指针，whence为0表示文件开头，1当前位置，2文件末尾。\\ntell()返回指针当前位置的字节偏移量。', '["with open(\\"data.txt\\", \\"r\\") as f:\\n    f.seek(10)\\n    pos = f.tell()", "file = open(\\"file.txt\\", \\"rb\\")\\nfile.seek(-5, 2)\\ncontent = file.read()\\nfile.close()"]', '["10", "b\\"末尾数据\\""]'),
('python', 113, 'intermediate', 1, '检查文件是否存在', '["文件","存在性","os模块"]', '使用os.path.exists()函数检查文件或目录是否存在。', '需要导入os模块。\\nexists()返回布尔值，True表示路径存在。\\n还可以使用os.path.isfile()和os.path.isdir()区分文件和目录。', '["import os\\nif os.path.exists(\\"file.txt\\"):\\n    print(\\"文件存在\\")", "path = \\"data.txt\\"\\nexists = os.path.exists(path)"]', '["\\"文件存在\\"", "True"]'),
('python', 114, 'intermediate', 1, '文件重命名和删除', '["文件","操作","重命名","删除"]', '使用os.rename()和os.remove()进行文件重命名和删除。', 'os.rename(src, dst)重命名或移动文件。\\nos.remove(path)删除文件，需确保文件存在。\\n操作可能引发OSError，建议先检查存在性。', '["import os\\nos.rename(\\"old.txt\\", \\"new.txt\\")", "if os.path.exists(\\"temp.txt\\"):\\n    os.remove(\\"temp.txt\\")"]', '["", ""]'),
('python', 115, 'intermediate', 1, '列出目录内容', '["目录","列表","os模块"]', '使用os.listdir()获取指定目录中的文件和子目录列表。', '返回路径名称的列表，不包括特殊条目.和..。\\n可以结合os.path.join()构建完整路径。\\n使用os.scandir()可获得更高效的迭代器。', '["import os\\nentries = os.listdir(\\".\\")", "for entry in os.listdir(\\"/path/to/dir\\"):\\n    print(entry)"]', '["[\\"file1.txt\\", \\"folder1\\"]", "\\"file1.txt\\\\n\\"\\"folder1\\\\n\\""]'),
('python', 116, 'intermediate', 1, '创建和删除目录', '["目录","创建","删除","os模块"]', '使用os.mkdir()创建单个目录，os.rmdir()删除空目录。', 'mkdir(path)创建目录，如果已存在会引发FileExistsError。\\nrmdir(path)删除空目录，非空目录会引发OSError。\\n使用os.makedirs()可递归创建多级目录。', '["import os\\nos.mkdir(\\"new_dir\\")", "os.rmdir(\\"empty_dir\\")"]', '["", ""]'),
('python', 117, 'intermediate', 1, '路径拼接和规范化', '["路径","操作","os.path"]', '使用os.path.join()拼接路径，os.path.abspath()获取绝对路径。', 'join()根据操作系统自动使用正确的分隔符拼接路径组件。\\nabspath(path)返回规范化绝对路径，解析符号链接。\\n还有os.path.normpath()用于规范化路径字符串。', '["import os\\nfull_path = os.path.join(\\"folder\\", \\"sub\\", \\"file.txt\\")", "abs_path = os.path.abspath(\\"relative.txt\\")"]', '["\\"folder/sub/file.txt\\"", "\\"/home/user/relative.txt\\""]'),
('python', 118, 'intermediate', 1, '使用shutil复制文件', '["文件","复制","shutil"]', '使用shutil.copy()或shutil.copy2()复制文件，保留元数据。', 'shutil模块提供高级文件操作。\\ncopy(src, dst)复制文件内容，copy2()还复制元数据如时间戳。\\n可以复制到目录或具体文件路径。', '["import shutil\\nshutil.copy(\\"source.txt\\", \\"destination.txt\\")", "shutil.copy2(\\"src.txt\\", \\"backup/\\")"]', '["", ""]'),
('python', 119, 'intermediate', 1, '文件编码处理', '["文件","编码","文本"]', '在open()中指定encoding参数以正确处理不同编码的文本文件。', '默认编码取决于平台，常用UTF-8。\\n指定encoding=\\"utf-8\\"确保可移植性。\\n处理非ASCII字符时，编码错误可用errors参数处理。', '["with open(\\"file.txt\\", \\"r\\", encoding=\\"utf-8\\") as f:\\n    text = f.read()", "open(\\"data.txt\\", \\"w\\", encoding=\\"latin-1\\").write(\\"café\\")"]', '["\\"文件内容\\"", ""]'),
('python', 120, 'intermediate', 1, '创建临时文件', '["临时文件","tempfile"]', '使用tempfile模块安全创建临时文件和目录。', 'tempfile.TemporaryFile()创建临时文件，关闭后自动删除。\\nTemporaryDirectory()创建临时目录，上下文退出时清理。\\n适用于需要临时存储的场景。', '["import tempfile\\nwith tempfile.TemporaryFile(mode=\\"w+t\\") as tmp:\\n    tmp.write(\\"temp data\\")", "with tempfile.TemporaryDirectory() as tmpdir:\\n    filepath = os.path.join(tmpdir, \\"test.txt\\")"]', '["", ""]');